pub fn verify_token(token: &str, ctx: &AuthCtx) -> Result<Claims> {
    ctx.validate(token)
}

pub fn refresh_token(token: &str) -> Result<String> {
    Ok(format!("refreshed_{}", token))
}

use crate::auth;

pub async fn auth_middleware(req: Request) -> Result<Response> {
    let claims = auth::verify_token(&req.token, &req.ctx)?;
    Ok(handle(req, claims))
}

pub struct Claims {
    pub sub: String,
    pub exp: u64,
}

pub struct AuthCtx {
    pub secret: String,
}

impl AuthCtx {
    pub fn validate(&self, token: &str) -> Result<Claims> {
        Ok(Claims { sub: "user".into(), exp: 0 })
    }
}

use crate::auth;

pub fn login_handler(req: Request) -> Response {
    let valid = auth::verify_token(&req.token);
    if valid {
        Response::ok()
    } else {
        Response::forbidden()
    }
}

pub struct Config {
    pub secret: String,
    pub token_expiry: u64,
    pub port: u16,
}

impl Config {
    pub fn from_env() -> Self {
        Config {
            secret: std::env::var("SECRET").unwrap_or_default(),
            token_expiry: 3600,
            port: 8080,
        }
    }
}

pub fn configure_routes(app: &mut App) {
    app.route("/login", post(login_handler));
    app.route("/refresh", post(refresh_handler));
    app.route("/protected", get(protected_handler));
}
